def _eval(t: object) -> int:
    if isinstance(t, int):
        return t
    left = _eval(t["left"])
    right = _eval(t["right"])
    op = t["op"]
    if op == "+":
        return left + right
    if op == "-":
        return left - right
    if op == "*":
        return left * right
    if op == "/":
        return left // right
    raise ValueError(f"unknown op: {op}")

def eval_tree(expr: dict) -> str:
    try:
        return f"= {_eval(expr)}"
    except ZeroDivisionError:
        return "division by zero"
    except ValueError as e:
        return str(e)

